<?php namespace App\Http\Controllers\Api\Admin; use App\Http\Controllers\Controller; use App\Models\MenuItem; use Illuminate\Http\Request; class AdminMenuController extends Controller { public function index() { return MenuItem::all(); } public function store(Request $request) { return MenuItem::create($request->all()); } public function update(Request $request, MenuItem $menuItem) { $menuItem->update($request->all()); return $menuItem; } public function destroy($id) { MenuItem::destroy($id); return response()->noContent(); } }